        self.country = country
        super().__init__(plain_repr('*') if country is None else repr(country))

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        cleaned = self._delimiters_re.sub('', other)
        if not cleaned:
            return False

        has_plus = cleaned.startswith('+')
        digits = cleaned[1:] if has_plus else cleaned
        if not digits.isdigit():
            return False

        rules = self._country_rules.get(self.country.upper()) if self.country else None

        if rules is not None:
            if has_plus:
                return bool(rules['international'].match(digits))
            else:
                return bool(rules['national'].match(digits))
        elif self.country is not None:
            # unrecognised country code, fall back to generic international validation
            return has_plus and bool(self._generic_international_re.match(digits))
        else:
            if has_plus:
                return bool(self._generic_international_re.match(digits))
            else:
                return bool(self._generic_national_re.match(digits))


